pub struct CliResult {
    pub exit_code: i32,
    pub stdout: String,
    pub stderr: String,
}

pub fn execute_cli(
    paths: &[String],
    format_str: &str,
    lang: Option<&str>,
    config: Config,
    run_fn: impl Fn(&[String], &Config) -> RunResult,
) -> CliResult {
    let format = match parse_output_format(format_str) {
        Ok(f) => f,
        Err(e) => {
            return CliResult {
                exit_code: 2,
                stdout: String::new(),
                stderr: format!("error: {}", e),
            };
        }
    };

    if let Some(lang) = lang {
        if let Err(e) = validate_lang(lang) {
            return CliResult {
                exit_code: 2,
                stdout: String::new(),
                stderr: format!("error: {}", e),
            };
        }
    }

    let config = Config { format, ..config };

    match run_fn(paths, &config) {
        RunResult::Clean => CliResult {
            exit_code: 0,
            stdout: if matches!(config.format, OutputFormat::Json) {
                "[]".to_string()
            } else {
                String::new()
            },
            stderr: String::new(),
        },
        RunResult::Duplicates(pairs) => CliResult {
            exit_code: 1,
            stdout: match config.format {
                OutputFormat::Text => format_text(&pairs),
                OutputFormat::Json => format_json(&pairs),
            },
            stderr: String::new(),
        },
        RunResult::Error(msg) => CliResult {
            exit_code: 2,
            stdout: String::new(),
            stderr: format!("error: {}", msg),
        },
    }
}

