pub struct CliResult {
    pub exit_code: i32,
    pub stdout: String,
    pub stderr: String,
}

pub fn execute_cli(
    paths: &[String],
    format_str: &str,
    lang: Option<&str>,
    config: Config,
    run_fn: impl Fn(&[String], &Config) -> RunResult,
) -> CliResult {
    let format = match parse_output_format(format_str) {
        Ok(f) => f,
        Err(e) => {
            return CliResult {
                exit_code: 2,
                stdout: String::new(),
                stderr: format!("error: {}", e),
            };
        }
    };

    if let Some(lang) = lang {
        if let Err(e) = validate_lang(lang) {
            return CliResult {
                exit_code: 2,
                stdout: String::new(),
                stderr: format!("error: {}", e),
            };
        }
    }

    let config = Config { format, ..config };

    match run_fn(paths, &config) {
        RunResult::Clean => CliResult {
            exit_code: 0,
            stdout: if matches!(config.format, OutputFormat::Json) {
                "[]".to_string()
            } else {
                String::new()
            },
            stderr: String::new(),
        },
        RunResult::Duplicates(pairs) => CliResult {
            exit_code: 1,
            stdout: match config.format {
                OutputFormat::Text => format_text(&pairs),
                OutputFormat::Json => format_json(&pairs),
            },
            stderr: String::new(),
        },
        RunResult::Error(msg) => CliResult {
            exit_code: 2,
            stdout: String::new(),
            stderr: format!("error: {}", msg),
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn jaccard_identical_sets_returns_one() {
        let a = vec![1u64, 2, 3];
        let b = vec![1u64, 2, 3];
        let score = jaccard(&a, &b);
        assert!((score - 1.0).abs() < 1e-9);
    }

    #[test]
    fn jaccard_disjoint_sets_returns_zero() {
        let a = vec![1u64, 2, 3];
        let b = vec![4u64, 5, 6];
        let score = jaccard(&a, &b);
        assert!(score < 1e-9);

